//! Deterministic, cross-process-stable hash of a `Module` for the
//! HIR-addressable object cache (issue #686).
//!
//! Contract:
//! - Same HIR → same hash, in the same process and across processes.
//! - Different HIR (any field that can affect generated bytes) → different hash.
//! - `HashMap` iteration order MUST NOT leak — keys are sorted before emit.
//! - No `Debug`, no `serde`, no `std::hash::Hash` on unordered structures.
//!
//! Adding a new HIR variant must force a build break in this file. To make
//! that the case, every `match` over a HIR enum is exhaustive (no wildcards
//! `_ =>`), and each variant is given an explicit `u16` tag. A new variant
//! → unhandled match arm → compile error.
//!
//! Used by `compute_object_cache_key` to fingerprint the post-transform
//! HIR that `perry_codegen::compile_module` actually consumes.

use crate::ir::*;
use perry_types::{FunctionType, ObjectType, PropertyInfo, Type, TypeParam};

/// Streaming hasher — minimal API so any djb2/fnv/blake variant can plug in.
pub trait StableHasher {
    fn write(&mut self, bytes: &[u8]);
    fn finish(&self) -> u64;
}

/// Convenience: hash a module to a `u64` using the default djb2-equivalent.
pub fn hash_module(m: &Module) -> u64 {
    let mut h = Djb2Hasher::new();
    hash_module_with(m, &mut h);
    h.finish()
}

/// Streaming variant — fold the HIR hash into an existing `StableHasher`.
pub fn hash_module_with<H: StableHasher>(m: &Module, h: &mut H) {
    SH::hash(m, h);
}

/// Local djb2 implementation, mirrored from
/// `crates/perry/src/commands/compile/object_cache.rs:63-87`. Kept here so
/// `perry-hir` doesn't depend on `perry`. Both must agree on the algorithm
/// for the cross-process determinism test to be meaningful.
pub struct Djb2Hasher {
    h: u64,
}

impl Djb2Hasher {
    pub fn new() -> Self {
        Self { h: 5381 }
    }
}

impl Default for Djb2Hasher {
    fn default() -> Self {
        Self::new()
    }
}

impl StableHasher for Djb2Hasher {
    fn write(&mut self, bytes: &[u8]) {
        for b in bytes {
            self.h = self.h.wrapping_mul(33).wrapping_add(*b as u64);
        }
    }
    fn finish(&self) -> u64 {
        self.h
    }
}

// --- Trait + primitive impls ----------------------------------------------

trait SH {
    fn hash<H: StableHasher>(&self, h: &mut H);
}

#[inline]
fn tag<H: StableHasher>(h: &mut H, t: u16) {
    h.write(&t.to_le_bytes());
}

impl SH for bool {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&[*self as u8]);
    }
}

impl SH for u8 {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&[*self]);
    }
}

impl SH for u32 {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&self.to_le_bytes());
    }
}

impl SH for usize {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&(*self as u64).to_le_bytes());
    }
}

impl SH for i64 {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&self.to_le_bytes());
    }
}

impl SH for f64 {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        // Canonicalize NaN to a single bit pattern so two NaN-producing
        // sources don't accidentally diverge on bit-payload alone.
        let bits = if self.is_nan() {
            f64::NAN.to_bits()
        } else if *self == 0.0 {
            // Treat +0.0 and -0.0 as equal (matches JS ===).
            0u64
        } else {
            self.to_bits()
        };
        h.write(&bits.to_le_bytes());
    }
}

impl SH for str {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&(self.len() as u64).to_le_bytes());
        h.write(self.as_bytes());
    }
}

impl SH for String {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        SH::hash(self.as_str(), h);
    }
}

impl<T: SH> SH for Box<T> {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        SH::hash(self.as_ref(), h);
    }
}

impl<T: SH> SH for Vec<T> {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        h.write(&(self.len() as u64).to_le_bytes());
        for item in self {
            item.hash(h);
        }
    }
}

impl<T: SH> SH for Option<T> {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        match self {
            None => tag(h, 0),
            Some(v) => {
                tag(h, 1);
                v.hash(h);
            }
        }
    }
}

impl<A: SH, B: SH> SH for (A, B) {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        self.0.hash(h);
        self.1.hash(h);
    }
}

impl<A: SH, B: SH, C: SH> SH for (A, B, C) {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        self.0.hash(h);
        self.1.hash(h);
        self.2.hash(h);
    }
}

// --- Module ----------------------------------------------------------------

impl SH for Module {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        let Module {
            name,
            imports,
            exports,
            classes,
            interfaces,
            type_aliases,
            enums,
            globals,
            functions,
            init,
            exported_native_instances,
            exported_func_return_native_instances,
            exported_objects,
            exported_functions,
            widgets,
            uses_fetch,
            uses_webassembly,
            extern_funcs,
            init_was_unrolled,
            has_top_level_await,
            init_kind,
        } = self;
        name.hash(h);
        imports.hash(h);
        exports.hash(h);
        classes.hash(h);
        interfaces.hash(h);
        type_aliases.hash(h);
        enums.hash(h);
        globals.hash(h);
        functions.hash(h);
        init.hash(h);
        exported_native_instances.hash(h);
        exported_func_return_native_instances.hash(h);
        exported_objects.hash(h);
        exported_functions.hash(h);
        widgets.hash(h);
        uses_fetch.hash(h);
        uses_webassembly.hash(h);
        extern_funcs.hash(h);
        init_was_unrolled.hash(h);
        has_top_level_await.hash(h);
        init_kind.hash(h);
    }
}

impl SH for ModuleInitKind {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        match self {
            ModuleInitKind::Eager => tag(h, 0),
            ModuleInitKind::Deferred => tag(h, 1),
        }
    }
}

// --- Imports / Exports / ModuleKind ---------------------------------------

impl SH for ModuleKind {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        match self {
            ModuleKind::NativeCompiled => tag(h, 0),
            ModuleKind::NativeRust => tag(h, 1),
            ModuleKind::Interpreted => tag(h, 2),
        }
    }
}

impl SH for Import {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        let Import {
            source,
            specifiers,
            is_native,
            module_kind,
            resolved_path,
            type_only,
            is_dynamic,
        } = self;
        source.hash(h);
        specifiers.hash(h);
        is_native.hash(h);
        module_kind.hash(h);
        resolved_path.hash(h);
        type_only.hash(h);
        is_dynamic.hash(h);
    }
}

impl SH for ImportSpecifier {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        match self {
            ImportSpecifier::Named { imported, local } => {
                tag(h, 0);
                imported.hash(h);
                local.hash(h);
            }
            ImportSpecifier::Default { local } => {
                tag(h, 1);
                local.hash(h);
            }
            ImportSpecifier::Namespace { local } => {
                tag(h, 2);
                local.hash(h);
            }
        }
    }
}

impl SH for Export {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        match self {
            Export::Named { local, exported } => {
                tag(h, 0);
                local.hash(h);
                exported.hash(h);
            }
            Export::ReExport {
                source,
                imported,
                exported,
            } => {
                tag(h, 1);
                source.hash(h);
                imported.hash(h);
                exported.hash(h);
            }
            Export::ExportAll { source } => {
                tag(h, 2);
                source.hash(h);
            }
            Export::NamespaceReExport { source, name } => {
                tag(h, 3);
                source.hash(h);
                name.hash(h);
            }
        }
    }
}

// --- Type system (from perry-types) ---------------------------------------

impl SH for Type {
    fn hash<H: StableHasher>(&self, hh: &mut H) {
        match self {
            Type::Void => tag(hh, 0),
            Type::Null => tag(hh, 1),
            Type::Boolean => tag(hh, 2),
            Type::Number => tag(hh, 3),
            Type::Int32 => tag(hh, 4),
            Type::BigInt => tag(hh, 5),
            Type::String => tag(hh, 6),
            Type::Symbol => tag(hh, 7),
            Type::Array(t) => {
                tag(hh, 8);
                t.as_ref().hash(hh);
            }
            Type::Tuple(ts) => {
                tag(hh, 9);
                ts.hash(hh);
            }
            Type::Object(o) => {
                tag(hh, 10);
                o.hash(hh);
            }
            Type::Function(f) => {
                tag(hh, 11);
                f.hash(hh);
            }
            Type::Union(ts) => {
                tag(hh, 12);
                ts.hash(hh);
            }
            Type::Promise(t) => {
                tag(hh, 13);
                t.as_ref().hash(hh);
            }
            Type::Any => tag(hh, 14),
            Type::Unknown => tag(hh, 15),
            Type::Never => tag(hh, 16),
            Type::Named(s) => {
                tag(hh, 17);
                s.hash(hh);
            }
            Type::TypeVar(s) => {
                tag(hh, 18);
                s.hash(hh);
            }
            Type::Generic { base, type_args } => {
                tag(hh, 19);
                base.hash(hh);
                type_args.hash(hh);
            }
        }
    }
}

impl SH for TypeParam {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        let TypeParam {
            name,
            constraint,
            default,
        } = self;
        name.hash(h);
        match constraint {
            None => tag(h, 0),
            Some(t) => {
                tag(h, 1);
                t.as_ref().hash(h);
            }
        }
        match default {
            None => tag(h, 0),
            Some(t) => {
                tag(h, 1);
                t.as_ref().hash(h);
            }
        }
    }
}

impl SH for ObjectType {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        let ObjectType {
            name,
            properties,
            index_signature,
        } = self;
        name.hash(h);
        // CRITICAL: properties is a HashMap. Sort by key before emit so
        // insertion order does not leak. This is the entire reason the
        // HIR hash is meaningful as a cache key (#686).
        let mut entries: Vec<(&String, &PropertyInfo)> = properties.iter().collect();
        entries.sort_by(|a, b| a.0.cmp(b.0));
        h.write(&(entries.len() as u64).to_le_bytes());
        for (k, v) in entries {
            k.hash(h);
            v.hash(h);
        }
        match index_signature {
            None => tag(h, 0),
            Some(t) => {
                tag(h, 1);
                t.as_ref().hash(h);
            }
        }
    }
}

impl SH for PropertyInfo {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        let PropertyInfo {
            ty,
            optional,
            readonly,
        } = self;
        ty.hash(h);
        optional.hash(h);
        readonly.hash(h);
    }
}

impl SH for FunctionType {
    fn hash<H: StableHasher>(&self, h: &mut H) {
        let FunctionType {
            params,
            return_type,
            is_async,
            is_generator,
        } = self;
        params.hash(h);
        return_type.as_ref().hash(h);
        is_async.hash(h);
        is_generator.hash(h);
    }
}

